import logging
import os
from typing import Optional
from urllib.parse import unquote
from azure.storage.blob import BlobServiceClient
from azure.functions import HttpRequest, HttpResponse

# Configuration
ALLOWED_CONTAINERS = os.environ.get("ALLOWED_CONTAINERS", "").split(",")
ALLOWED_EXTENSIONS = os.environ.get("ALLOWED_EXTENSIONS", "").split(",")
BLOB_CONNECTION_STRING = os.environ.get("BLOB_CONNECTION_STRING")

# Initialize blob service client
blob_service_client = BlobServiceClient.from_connection_string(BLOB_CONNECTION_STRING)

def validate_blob_path(blob_path: str) -> bool:
    """Validate blob path to prevent directory traversal and unauthorized access."""
    if not blob_path:
        return False
    
    # Decode URL encoded path
    decoded_path = unquote(blob_path)
    
    # Check for directory traversal attempts
    if ".." in decoded_path:
        return False
    
    # Check if path starts with allowed containers
    if not any(decoded_path.startswith(container + "/") for container in ALLOWED_CONTAINERS):
        return False
    
    # Validate file extension if extensions are specified
    if ALLOWED_EXTENSIONS and len(ALLOWED_EXTENSIONS) > 0:
        file_extension = os.path.splitext(decoded_path)[1].lower()
        if file_extension and file_extension not in ALLOWED_EXTENSIONS:
            return False
    
    return True

def get_blob_content(container_name: str, blob_name: str) -> Optional[bytes]:
    """Retrieve blob content securely."""
    try:
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name
        )
        return blob_client.download_blob().readall()
    except Exception as e:
        logging.error(f"Error retrieving blob {blob_name}: {str(e)}")
        return None

def main(req: HttpRequest) -> HttpResponse:
    """HTTP trigger function to serve files from Azure Blob Storage."""
    logging.info('Python HTTP trigger function processed a request.')
    
    # Get blob path from query parameters
    blob_path = req.params.get('path')
    
    if not blob_path:
        return HttpResponse(
            "Blob path is required.",
            status_code=400
        )
    
    # Validate blob path
    if not validate_blob_path(blob_path):
        return HttpResponse(
            "Invalid or unauthorized blob path.",
            status_code=403
        )
    
    # Extract container and blob name
    try:
        container_name, blob_name = blob_path.split("/", 1)
    except ValueError:
        return HttpResponse(
            "Invalid blob path format.",
            status_code=400
        )
    
    # Retrieve blob content
    content = get_blob_content(container_name, blob_name)
    
    if content is None:
        return HttpResponse(
            "Blob not found or error occurred.",
            status_code=404
        )
    
    # Determine content type based on file extension
    content_type = "application/octet-stream"
    file_extension = os.path.splitext(blob_name)[1].lower()
    
    content_type_map = {
        ".txt": "text/plain",
        ".json": "application/json",
        ".xml": "application/xml",
        ".html": "text/html",
        ".css": "text/css",
        ".js": "application/javascript",
        ".png": "image/png",
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".gif": "image/gif",
        ".pdf": "application/pdf",
        ".zip": "application/zip",
        ".csv": "text/csv"
    }
    
    if file_extension in content_type_map:
        content_type = content_type_map[file_extension]
    
    return HttpResponse(
        content,
        status_code=200,
        headers={"Content-Type": content_type}
    )